@startuml
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  BorderColor Black
  FontColor Black
}

package "Aggregate-Buch" {
  class "Buch" {
    <<root entity>>
    "C" Buch
  }

  class "AutorID" {
    "C" AutorID
    <<value>>
  }

  class "BuchID" {
    "C" BuchID
    <<value>>
  }

  class "Kapitel" {
    "C" Kapitel
    <<entity>>
  }

  class "KapitelID" {
    "C" KapitelID
    <<value>>
  }

  class "Status" {
    "E" Status
    <<value>>
  }

  Buch --|> AutorID :
  Buch --|> BuchID :
  Buch --|> Kapitel :
  Kapitel --|> KapitelID :
  Kapitel --|> Status :
  Buch ..> Status :
}

@enduml
